/*!50003 DROP PROCEDURE IF EXISTS `sp_absen` */;
/*!50003 SET @saved_cs_client      = @@character_set_client */ ;
/*!50003 SET @saved_cs_results     = @@character_set_results */ ;
/*!50003 SET @saved_col_connection = @@collation_connection */ ;
/*!50003 SET character_set_client  = utf8mb4 */ ;
/*!50003 SET character_set_results = utf8mb4 */ ;
/*!50003 SET collation_connection  = utf8mb4_general_ci */ ;
/*!50003 SET @saved_sql_mode       = @@sql_mode */ ;
/*!50003 SET sql_mode              = 'IGNORE_SPACE,STRICT_TRANS_TABLES,ERROR_FOR_DIVISION_BY_ZERO,NO_AUTO_CREATE_USER,NO_ENGINE_SUBSTITUTION' */ ;
DELIMITER ;;
CREATE DEFINER=`root`@`localhost` PROCEDURE `sp_absen`(
    IN p_employee_id BIGINT,
    IN p_mode VARCHAR(10),   -- 'IN' / 'OUT'
    IN p_work_date DATE
)
BEGIN

    DECLARE v_shift_id BIGINT;
    DECLARE v_schedule_type VARCHAR(20);
    DECLARE v_check_in DATETIME;
    DECLARE v_check_out DATETIME;
    DECLARE v_time_in TIME;
    DECLARE v_time_out TIME;
    DECLARE v_late INT DEFAULT 0;
    DECLARE v_early INT DEFAULT 0;
    DECLARE v_shift_in_dt DATETIME;
    DECLARE v_shift_out_dt DATETIME;
    declare v_working_id VARCHAR(50);
    declare v_grade_id VARCHAR(50);
    declare v_position_id VARCHAR(50);
    declare v_education_id VARCHAR(50);
    
    
    -- =============================
    -- AMBIL DATA POSITION GRADE  
    -- WORKING STATUS
    -- =============================
    select working_id , grade_id , position_id ,education_id
    INTO v_working_id, v_grade_id , v_position_id,v_education_id
    from vw_employee
    where employee_id = p_employee_id ;
    
    
    -- =============================
    -- VALIDASI TANGGAL
    -- =============================
    IF p_work_date > CURDATE() THEN
        SIGNAL SQLSTATE '45000'
        SET MESSAGE_TEXT = 'Tidak boleh absen untuk tanggal masa depan';
    END IF;

    -- =============================
    -- AMBIL SCHEDULE
    -- =============================
    SELECT shift_id, schedule_type
    INTO v_shift_id, v_schedule_type
    FROM trn_employee_schedule
    WHERE employee_id = p_employee_id
      AND work_date = p_work_date
    LIMIT 1;

    IF v_schedule_type IS NULL THEN
        SIGNAL SQLSTATE '45000'
        SET MESSAGE_TEXT = 'Schedule tidak ditemukan';
    END IF;

    IF v_schedule_type IN ('OFF','HOLIDAY') THEN
        SIGNAL SQLSTATE '45000'
        SET MESSAGE_TEXT = 'Hari ini libur / OFF';
    END IF;

    -- =============================
    -- AMBIL SHIFT
    -- =============================
    SELECT time_in, time_out
    INTO v_time_in, v_time_out
    FROM mst_shift
    WHERE shift_id = v_shift_id
    LIMIT 1;

    -- datetime shift
    SET v_shift_in_dt = CONCAT(p_work_date, ' ', v_time_in);

    SET v_shift_out_dt = 
        CASE 
            WHEN v_time_out < v_time_in 
                THEN CONCAT(DATE_ADD(p_work_date, INTERVAL 1 DAY), ' ', v_time_out)
            ELSE CONCAT(p_work_date, ' ', v_time_out)
        END;

    -- =============================
    -- AMBIL ATTENDANCE
    -- =============================
    SELECT check_in, check_out
    INTO v_check_in, v_check_out
    FROM trn_attendance
    WHERE employee_id = p_employee_id
      AND work_date = p_work_date
    LIMIT 1;

    
    

    -- =============================
    -- MODE ABSEN IN
    -- =============================
    IF p_mode = 'IN' THEN

        IF v_check_in IS NOT NULL THEN
            SIGNAL SQLSTATE '45000'
            SET MESSAGE_TEXT = 'Sudah absen masuk';
        END IF;

        -- hitung keterlambatan
        SET v_late = GREATEST(
            TIMESTAMPDIFF(MINUTE, v_shift_in_dt, NOW()),
            0
        );

        INSERT INTO trn_attendance (
            employee_id,
            work_date,
            check_in,
            late_minutes,
            attendance_status,
            attendance_code
        )
        VALUES (
            p_employee_id,
            p_work_date,
            NOW(),
            v_late,
            CASE 
                WHEN v_late > 0 THEN 'LATE'
                ELSE 'PRESENT'
            end,
            'TL'
        )
        ON DUPLICATE KEY UPDATE
            check_in = IFNULL(check_in, VALUES(check_in));

    -- =============================
    -- MODE ABSEN OUT
    -- =============================
    ELSEIF p_mode = 'OUT' THEN

        -- =============================
        -- HITUNG EARLY LEAVE
        -- =============================
        SET v_early = GREATEST(
            TIMESTAMPDIFF(MINUTE, NOW(), v_shift_out_dt),
            0
        );

        -- =============================
        -- CASE 1: BELUM ADA RECORD
        -- =============================
        IF v_check_in IS NULL THEN

            SET v_late = GREATEST(
                TIMESTAMPDIFF(MINUTE, v_shift_in_dt, NOW()),
                0
            );

            INSERT INTO trn_attendance (
                employee_id,
                work_date,
                check_in,
                check_out,
                late_minutes,
                early_leave_minutes,
                attendance_code
            )
            VALUES (
                p_employee_id,
                p_work_date,
                NULL, -- auto check-in
                NOW(),
                v_late,
                v_early,
--                 CASE 
--                     WHEN v_late > 0 THEN 'LATE'
--                     ELSE 'PRESENT'
--                 END
                'TL'
            )
            ON DUPLICATE KEY UPDATE
                check_out = NOW(),
                early_leave_minutes = v_early;

        ELSE

            -- =============================
            -- CASE 2: NORMAL OUT
            -- =============================
            UPDATE trn_attendance
            SET 
                check_out = NOW(),
                early_leave_minutes = v_early,
--                 attendance_status = CASE 
--                     WHEN late_minutes > 0 THEN 'LATE'
--                     WHEN v_early > 0 THEN 'EARLY'
--                     ELSE 'PRESENT'
--                 END,
                attendance_code='H',
                updated_at = CURRENT_TIMESTAMP
            WHERE employee_id = p_employee_id
              AND work_date = p_work_date;

        END IF;

    -- INSERT ALLOWANCE DAILY 
    call sp_insert_allowance_attendance (p_employee_id,v_shift_id,p_work_date);  
    
    -- INSERT ALLOWANCE BY POSITION
    call sp_insert_allowance_position (p_employee_id,v_position_id,v_grade_id,v_working_id,v_education_id,p_work_date);
	
    
    ELSE
        SIGNAL SQLSTATE '45000'
        SET MESSAGE_TEXT = 'Mode harus IN atau OUT';
    END IF;
    

END ;;
DELIMITER ;
/*!50003 SET sql_mode              = @saved_sql_mode */ ;
/*!50003 SET character_set_client  = @saved_cs_client */ ;
/*!50003 SET character_set_results = @saved_cs_results */ ;
/*!50003 SET collation_connection  = @saved_col_connection */ ;
/*!50003 DROP PROCEDURE IF EXISTS `sp_calculate_overtime` */;
/*!50003 SET @saved_cs_client      = @@character_set_client */ ;
/*!50003 SET @saved_cs_results     = @@character_set_results */ ;
/*!50003 SET @saved_col_connection = @@collation_connection */ ;
/*!50003 SET character_set_client  = utf8mb4 */ ;
/*!50003 SET character_set_results = utf8mb4 */ ;
/*!50003 SET collation_connection  = utf8mb4_general_ci */ ;
/*!50003 SET @saved_sql_mode       = @@sql_mode */ ;
/*!50003 SET sql_mode              = 'IGNORE_SPACE,STRICT_TRANS_TABLES,ERROR_FOR_DIVISION_BY_ZERO,NO_AUTO_CREATE_USER,NO_ENGINE_SUBSTITUTION' */ ;
DELIMITER ;;
CREATE DEFINER=`root`@`localhost` PROCEDURE `sp_calculate_overtime`(
    IN p_employee_id BIGINT,
    IN p_work_date DATE
)
BEGIN
    DECLARE v_total_minutes      DECIMAL(10,2);
    DECLARE v_total_hours        DECIMAL(5,2)  DEFAULT 0;
    DECLARE v_total_hours_actual DECIMAL(5,2)  DEFAULT 0;
    DECLARE v_total_hours_rounded DECIMAL(5,2) DEFAULT 0;
    DECLARE v_overtime_index     DECIMAL(8,2)  DEFAULT 0;
    DECLARE v_group_id           BIGINT;
	DECLARE v_allowance_id       BIGINT;
    DECLARE v_rule_id            BIGINT;
    DECLARE v_rule_min_minutes   DECIMAL(10,2);
    DECLARE v_day_type           VARCHAR(20);
    DECLARE v_overtime_type      VARCHAR(20);
    DECLARE v_check_in           DATETIME;
    DECLARE v_check_out          DATETIME;
    DECLARE v_hour_counter       INT           DEFAULT 1;
    DECLARE v_remaining_hours    DECIMAL(10,2);
    DECLARE v_multiplier         DECIMAL(5,2);
    DECLARE v_current_portion    DECIMAL(10,2);
	declare v_amount             DECIMAL(10,2);
    declare v_pembagi_overtime   DECIMAL(10,2);
    declare v_basic_sallary      DECIMAL(10,2);
	declare v_hour_price 		 DECIMAL(10,2);
    -- Ambil data absen
    SELECT check_in, check_out
    INTO v_check_in, v_check_out
    FROM trn_attendance
    WHERE employee_id = p_employee_id AND work_date = p_work_date;

    -- Ambil day_type, overtime_type dari trn_overtime
    SELECT day_type, overtime_type
    INTO v_day_type, v_overtime_type
    FROM trn_overtime
    WHERE employee_id = p_employee_id AND work_date = p_work_date;

    -- Ambil group_id dan rule_id berdasarkan employee & day_type
    SELECT a.group_id, b.rule_id 
    INTO v_group_id, v_rule_id 
    FROM mst_employee_overtime a
    LEFT JOIN mst_overtime_group_detail b
        ON b.group_id = a.group_id
        AND b.working_day_type = v_day_type
        AND b.overtime_category = v_overtime_type
    WHERE a.employee_id = p_employee_id;

    -- Hanya hitung jika absen lengkap
    IF v_check_in IS NOT NULL AND v_check_out IS NOT NULL THEN

        -- Ambil minimal menit lembur dari rule
        SELECT a.min_minutes , a.fixed_amount , a.salary_allowance_id 
        INTO v_rule_min_minutes , v_amount , v_allowance_id
        FROM mst_overtime_rule a
        WHERE a.id = v_rule_id
          AND a.overtime_category = v_day_type
          AND a.overtime_type = v_overtime_type;

        -- Hitung total menit lembur aktual
        SELECT
            COALESCE(TIMESTAMPDIFF(MINUTE, early_start,   early_end),   0) +
            COALESCE(TIMESTAMPDIFF(MINUTE, late_start,    late_end),    0) +
            COALESCE(TIMESTAMPDIFF(MINUTE, holiday_start, holiday_end), 0)
        INTO v_total_minutes
        FROM trn_overtime
        WHERE employee_id = p_employee_id AND work_date = p_work_date;

        -- Jam aktual (tanpa pembulatan, untuk disimpan sebagai referensi)
        SET v_total_hours_actual = v_total_minutes / 60;

        -- Tentukan jam dasar hitung (FIXED pakai min_minutes, REGULAR pakai aktual)
        IF v_overtime_type = 'FIXED' THEN
            IF v_total_minutes < v_rule_min_minutes THEN
                SET v_total_hours = v_total_hours_actual;
            ELSE
                SET v_total_hours = v_rule_min_minutes / 60;
            END IF;
        ELSE
            SET v_total_hours = v_total_hours_actual;
        END IF;

        -- Pembulatan ke 0.5 terdekat ke bawah (dasar hitung indeks)
        -- Contoh: 2.15 → 2.0 | 2.50 → 2.5 | 2.75 → 2.5 | 2.87 → 2.5 | 3.40 → 3.0
        SET v_total_hours_rounded = FLOOR(v_total_hours * 2) / 2;

        -- Hitung overtime_index dengan loop per jam
        -- v_hour_counter = INT untuk lookup tabel rate (selalu bilangan bulat)
        -- v_remaining_hours = DECIMAL untuk menangani pecahan 0.5
        SET v_overtime_index  = 0;
        SET v_hour_counter    = 1;
        SET v_remaining_hours = v_total_hours_rounded;

        WHILE v_remaining_hours > 0 DO

            -- Ambil multiplier untuk jam ke-n (berdasarkan hour_counter integer)
            SELECT a.multiplier
            INTO v_multiplier
            FROM vw_mst_overtime_rate a
            WHERE a.rule_id           = v_rule_id
              AND a.overtime_category = v_day_type
              AND a.overtime_type     = v_overtime_type
              AND a.hour_from         <= v_hour_counter
              AND (a.hour_to IS NULL OR a.hour_to >= v_hour_counter)
              AND a.is_active         = 1
            ORDER BY a.hour_from ASC
            LIMIT 1;

            -- Porsi jam iterasi ini: 1 jam penuh, atau sisa 0.5 di iterasi terakhir
            SET v_current_portion = LEAST(v_remaining_hours, 1);

            -- Indeks += porsi × multiplier
            SET v_overtime_index  = v_overtime_index + (v_current_portion * IFNULL(v_multiplier, 1));
            SET v_remaining_hours = v_remaining_hours - v_current_portion;

            -- hour_counter hanya naik jika porsi penuh (1 jam), bukan pecahan 0.5
            IF v_current_portion = 1 THEN
                SET v_hour_counter = v_hour_counter + 1;
            END IF;

        END WHILE;

    ELSE
        -- Absen tidak lengkap → lembur = 0
        SET v_total_hours_actual  = 0;
        SET v_total_hours_rounded = 0;
        SET v_overtime_index      = 0;
    END IF;

    -- Simpan hasil ke tabel
    -- total_hours_actual : jam mentah dari absen (untuk audit/transparansi)
    -- total_hours        : jam setelah pembulatan 0.5 (dasar hitung indeks & upah)
    -- overtime_index     : hasil perhitungan indeks
    UPDATE trn_overtime
    SET total_hours_actual = v_total_hours_actual,
        total_hours        = v_total_hours_rounded,
        overtime_index     = v_overtime_index
    WHERE employee_id = p_employee_id AND work_date = p_work_date;
    
    
    delete from trn_attendance_allowance
            WHERE employee_id = p_employee_id
              AND work_date = p_work_date
              AND allowance_id = v_allowance_id ; 
    -- Hitung Pembayaran Overtime 
    if v_overtime_type = 'FIXED' then 
       IF NOT EXISTS (
            SELECT 1 
            FROM trn_attendance_allowance
            WHERE employee_id = p_employee_id
              AND work_date = p_work_date
              AND allowance_id = v_allowance_id
        ) THEN
		  
         insert into trn_attendance_allowance 
    	 values (p_employee_id,p_work_date,v_allowance_id,v_amount,NOW(),'system');

        END IF;
    	
    else 
         set v_pembagi_overtime = 173;
         SELECT v.basic_salary
			INTO v_basic_sallary
			FROM vw_employee_basic_salary_by_date v
			WHERE v.employee_id = p_employee_id
			  AND p_work_date BETWEEN v.emp_start_date 
			                      AND IFNULL(v.emp_end_date, '9999-12-31')
			  AND p_work_date BETWEEN v.salary_start_date 
			                      AND IFNULL(v.salary_end_date, '9999-12-31')
			LIMIT 1;
         set v_hour_price = v_basic_sallary /  v_pembagi_overtime ;
         set v_amount = v_hour_price * v_overtime_index ;
         
    	 insert into trn_attendance_allowance 
    	 values (p_employee_id,p_work_date,v_allowance_id,v_amount,NOW(),'system');
    end if;

END ;;
DELIMITER ;
/*!50003 SET sql_mode              = @saved_sql_mode */ ;
/*!50003 SET character_set_client  = @saved_cs_client */ ;
/*!50003 SET character_set_results = @saved_cs_results */ ;
/*!50003 SET collation_connection  = @saved_col_connection */ ;
/*!50003 DROP PROCEDURE IF EXISTS `sp_calc_allowance_daily` */;
/*!50003 SET @saved_cs_client      = @@character_set_client */ ;
/*!50003 SET @saved_cs_results     = @@character_set_results */ ;
/*!50003 SET @saved_col_connection = @@collation_connection */ ;
/*!50003 SET character_set_client  = utf8mb4 */ ;
/*!50003 SET character_set_results = utf8mb4 */ ;
/*!50003 SET collation_connection  = utf8mb4_general_ci */ ;
/*!50003 SET @saved_sql_mode       = @@sql_mode */ ;
/*!50003 SET sql_mode              = 'IGNORE_SPACE,STRICT_TRANS_TABLES,ERROR_FOR_DIVISION_BY_ZERO,NO_AUTO_CREATE_USER,NO_ENGINE_SUBSTITUTION' */ ;
DELIMITER ;;
CREATE DEFINER=`root`@`localhost` PROCEDURE `sp_calc_allowance_daily`(IN p_employee_id BIGINT,
    IN p_start_date DATE,
    IN p_end_date DATE,
    in p_period_id int
)
begin 

    DECLARE v_allowance_id BIGINT;
    DECLARE v_component_code VARCHAR(50);
    DECLARE v_component_name VARCHAR(100);
    DECLARE v_component_type VARCHAR(1);
    DECLARE v_is_taxable TINYINT;
    DECLARE v_salary_amount DECIMAL(18,2);

    DECLARE done INT DEFAULT 0;

    -- cursor ambil allowance per type
    DECLARE cur_allowance CURSOR FOR
        SELECT 
            ta.allowance_id,
            SUM(ta.amount)
        FROM trn_attendance_allowance ta
        WHERE 
            ta.employee_id = p_employee_id
            AND ta.work_date BETWEEN p_start_date AND p_end_date
        GROUP BY ta.allowance_id;

    DECLARE CONTINUE HANDLER FOR NOT FOUND SET done = 1;

    OPEN cur_allowance;

    read_loop: LOOP

        FETCH cur_allowance INTO v_allowance_id, v_salary_amount;

        IF done THEN
            LEAVE read_loop;
        END IF;

        -- =========================
        -- AMBIL MASTER ALLOWANCE
        -- =========================
        SELECT 
            allowance_code,
            allowance_name,
            type,
            is_tax
        INTO 
            v_component_code,
            v_component_name,
            v_component_type,
            v_is_taxable
        FROM mst_allowance_component 
        WHERE id = v_allowance_id;

        -- =========================
        -- DELETE EXISTING
        -- =========================
        DELETE FROM payroll_employee_component
        WHERE 
            period_id = p_period_id
            AND employee_id = p_employee_id
            AND component_code = v_component_code;

        -- =========================
        -- INSERT
        -- =========================
        INSERT INTO payroll_employee_component (
            period_id,
            component_id,
            employee_id,
            component_code,
            component_name,
            component_type,
            amount,
            is_taxable,
            remarks,
            created_at,
            created_by
        )
        VALUES (
            p_period_id,
            v_allowance_id,
            p_employee_id,
            v_component_code,
            v_component_name,
            v_component_type,
            v_salary_amount,
            v_is_taxable,
            'ALLOWANCE',
            NOW(),
            ''
        );

    END LOOP;

    CLOSE cur_allowance;

end ;;
DELIMITER ;
/*!50003 SET sql_mode              = @saved_sql_mode */ ;
/*!50003 SET character_set_client  = @saved_cs_client */ ;
/*!50003 SET character_set_results = @saved_cs_results */ ;
/*!50003 SET collation_connection  = @saved_col_connection */ ;
/*!50003 DROP PROCEDURE IF EXISTS `sp_calc_allowance_monthly` */;
/*!50003 SET @saved_cs_client      = @@character_set_client */ ;
/*!50003 SET @saved_cs_results     = @@character_set_results */ ;
/*!50003 SET @saved_col_connection = @@collation_connection */ ;
/*!50003 SET character_set_client  = utf8mb4 */ ;
/*!50003 SET character_set_results = utf8mb4 */ ;
/*!50003 SET collation_connection  = utf8mb4_general_ci */ ;
/*!50003 SET @saved_sql_mode       = @@sql_mode */ ;
/*!50003 SET sql_mode              = 'IGNORE_SPACE,STRICT_TRANS_TABLES,ERROR_FOR_DIVISION_BY_ZERO,NO_AUTO_CREATE_USER,NO_ENGINE_SUBSTITUTION' */ ;
DELIMITER ;;
CREATE DEFINER=`root`@`localhost` PROCEDURE `sp_calc_allowance_monthly`(
    IN p_employee_id BIGINT,
    IN p_period_id INT,
    IN p_position_id VARCHAR(100),
    IN p_grade_id VARCHAR(100),
    IN p_working_id VARCHAR(100),
    IN p_education_id VARCHAR(100),
    IN p_start_date DATE,
    IN p_end_date DATE,
    IN p_join_date DATE,
    IN p_resign_date DATE
)
BEGIN

    -- =========================
    -- DECLARE (WAJIB DI ATAS)
    -- =========================
    DECLARE v_allowance_id BIGINT;
    DECLARE v_amount DECIMAL(18,2);

    DECLARE v_component_code VARCHAR(50);
    DECLARE v_component_name VARCHAR(100);
    DECLARE v_component_type VARCHAR(1);
    DECLARE v_is_taxable TINYINT;

    DECLARE v_total_days INT;
    DECLARE v_weekend_count INT DEFAULT 0;
    DECLARE v_holiday_count INT DEFAULT 0;
    DECLARE v_total_work_days INT DEFAULT 0;
    DECLARE v_employee_work_days INT DEFAULT 0;

    DECLARE v_date DATE;
    DECLARE v_salary_amount DECIMAL(18,2);

    DECLARE done INT DEFAULT 0;

    -- 🔥 cursor HARUS DI SINI
    DECLARE cur_allowance CURSOR FOR
        SELECT allowance_id, amount
        FROM mst_allowance_position
        WHERE 
            position_id = p_position_id
            AND grade_id = p_grade_id
            AND working_id = p_working_id
            AND education_id = p_education_id
            AND is_daily = 0
            AND start_date <= p_end_date
            AND IFNULL(end_date, p_end_date) >= p_start_date;

    -- 🔥 handler juga di atas
    DECLARE CONTINUE HANDLER FOR NOT FOUND SET done = 1;

    -- =========================
    -- LOGIC MULAI DI SINI
    -- =========================

    -- total hari
    SET v_total_days = DATEDIFF(p_end_date, p_start_date) + 1;

    SET v_date = p_start_date;

    WHILE v_date <= p_end_date DO
        IF DAYOFWEEK(v_date) IN (1,7) THEN
            SET v_weekend_count = v_weekend_count + 1;
        END IF;

        SET v_date = DATE_ADD(v_date, INTERVAL 1 DAY);
    END WHILE;

    SELECT COUNT(*)
    INTO v_holiday_count
    FROM mst_holiday h
    WHERE 
        h.is_active = 1
        AND h.holiday_date BETWEEN p_start_date AND p_end_date
        AND DAYOFWEEK(h.holiday_date) NOT IN (1,7);

    SET v_total_work_days = v_total_days - v_weekend_count - v_holiday_count;

    -- working day employee
    SET v_date = GREATEST(p_start_date, p_join_date);

    WHILE v_date <= LEAST(IFNULL(p_resign_date, p_end_date), p_end_date) DO

        IF DAYOFWEEK(v_date) NOT IN (1,7)
           AND NOT EXISTS (
                SELECT 1 FROM mst_holiday h 
                WHERE h.holiday_date = v_date AND h.is_active = 1
           )
        THEN
            SET v_employee_work_days = v_employee_work_days + 1;
        END IF;

        SET v_date = DATE_ADD(v_date, INTERVAL 1 DAY);

    END WHILE;

    -- =========================
    -- CURSOR EXECUTION
    -- =========================
    OPEN cur_allowance;

    read_loop: LOOP

        FETCH cur_allowance INTO v_allowance_id, v_amount;

        IF done THEN
            LEAVE read_loop;
        END IF;

        SELECT allowance_code, allowance_name, type, is_tax
        INTO v_component_code, v_component_name, v_component_type, v_is_taxable
        FROM mst_allowance_component
        WHERE id = v_allowance_id;

        IF v_total_work_days > 0 THEN
            SET v_salary_amount = ROUND(
                (v_amount / v_total_work_days) * v_employee_work_days,
                2
            );
        ELSE
            SET v_salary_amount = 0;
        END IF;

        DELETE FROM payroll_employee_component
        WHERE 
            period_id = p_period_id
            AND employee_id = p_employee_id
            AND component_code = v_component_code;

        INSERT INTO payroll_employee_component (
            period_id,
            employee_id,
            component_id,
            component_code,
            component_name,
            component_type,
            amount,
            is_taxable,
            remarks,
            created_at,
            created_by
        )
        VALUES (
            p_period_id,
            p_employee_id,
            v_allowance_id,
            v_component_code,
            v_component_name,
            v_component_type,
            v_salary_amount,
            v_is_taxable,
            'ALLOWANCE_PRORATE',
            NOW(),
            ''
        );

    END LOOP;

    CLOSE cur_allowance;

END ;;
DELIMITER ;
/*!50003 SET sql_mode              = @saved_sql_mode */ ;
/*!50003 SET character_set_client  = @saved_cs_client */ ;
/*!50003 SET character_set_results = @saved_cs_results */ ;
/*!50003 SET collation_connection  = @saved_col_connection */ ;
/*!50003 DROP PROCEDURE IF EXISTS `sp_calc_basic_salary` */;
/*!50003 SET @saved_cs_client      = @@character_set_client */ ;
/*!50003 SET @saved_cs_results     = @@character_set_results */ ;
/*!50003 SET @saved_col_connection = @@collation_connection */ ;
/*!50003 SET character_set_client  = utf8mb4 */ ;
/*!50003 SET character_set_results = utf8mb4 */ ;
/*!50003 SET collation_connection  = utf8mb4_general_ci */ ;
/*!50003 SET @saved_sql_mode       = @@sql_mode */ ;
/*!50003 SET sql_mode              = 'IGNORE_SPACE,STRICT_TRANS_TABLES,ERROR_FOR_DIVISION_BY_ZERO,NO_AUTO_CREATE_USER,NO_ENGINE_SUBSTITUTION' */ ;
DELIMITER ;;
CREATE DEFINER=`root`@`localhost` PROCEDURE `sp_calc_basic_salary`(
    IN p_employee_id BIGINT,
    IN p_start_date DATE,
    IN p_end_date DATE,
    IN p_join_date DATE,
    IN p_resign_date DATE,
    in p_period_id INT
)
BEGIN

    DECLARE v_total_work_days DECIMAL(18,2) DEFAULT 0;
    DECLARE v_employee_work_days DECIMAL(18,2) DEFAULT 0;
    DECLARE v_salary_status VARCHAR(20);
    DECLARE v_salary_amount DECIMAL(18,2);
	DECLARE p_basic_salary DECIMAL(18,2);
    declare v_sallary_id bigint ;
    
    declare v_component_code varchar(255);
    declare v_component_name varchar(255);
    declare v_component_type varchar(255);
    declare v_is_taxable bit;
        
    -- =========================
    -- TOTAL HARI KERJA DALAM PERIODE
    -- =========================
    DECLARE v_total_days INT;
	DECLARE v_weekend_count INT DEFAULT 0;
	DECLARE v_holiday_count INT DEFAULT 0;
	DECLARE v_date DATE;
    SET v_total_days = DATEDIFF(p_end_date, p_start_date) + 1;
    SET v_date = p_start_date;

	WHILE v_date <= p_end_date DO
	
	    -- 1 = Minggu, 7 = Sabtu
	    IF DAYOFWEEK(v_date) IN (1,7) THEN
	        SET v_weekend_count = v_weekend_count + 1;
	    END IF;
	
	    SET v_date = DATE_ADD(v_date, INTERVAL 1 DAY);
	
	END WHILE;
	
	SELECT COUNT(*)
	INTO v_holiday_count
	FROM mst_holiday h
	WHERE 
	    h.is_active = 1
	    AND h.holiday_date BETWEEN p_start_date AND p_end_date
	    AND DAYOFWEEK(h.holiday_date) NOT IN (1,7); 
	SET v_total_work_days = v_total_days 
                        - v_weekend_count 
                        - v_holiday_count;

    -- =========================
    -- HARI KERJA EMPLOYEE (PRORATE)
    -- =========================
    SELECT COUNT(*)
    INTO v_employee_work_days
    FROM vw_attendance_employee
    WHERE employee_id = p_employee_id
      AND work_date BETWEEN 
            GREATEST(p_start_date, p_join_date)
        AND LEAST(IFNULL(p_resign_date, p_end_date), p_end_date)
      AND schedule_type = 'WORK';
    
    
     -- =========================
    -- AMBIL BASIC SALLARY
    -- =========================
   	SELECT basic_salary,allowance_id 
	INTO p_basic_salary,v_sallary_id 
	FROM vw_employee_basic_salary_by_date
	WHERE employee_id = p_employee_id
	AND salary_start_date <= p_end_date
	AND IFNULL(salary_end_date, p_end_date) >= p_start_date
	LIMIT 1;

    -- =========================
    -- STATUS
    -- =========================
    IF v_employee_work_days = v_total_work_days THEN
        SET v_salary_status = 'FULL';

    ELSEIF p_join_date > p_start_date THEN
        SET v_salary_status = 'PRORATE_JOIN';

    ELSEIF p_resign_date IS NOT NULL AND p_resign_date < p_end_date THEN
        SET v_salary_status = 'PRORATE_RESIGN';

    ELSE
        SET v_salary_status = 'PRORATE';
    END IF;

    -- =========================
    -- PERHITUNGAN GAJI
    -- =========================
    IF v_total_work_days > 0 THEN
       SET v_salary_amount = ROUND(
		    (p_basic_salary / CAST(v_total_work_days AS DECIMAL(18,2))) 
		    * v_employee_work_days,
		    2
		);
    ELSE
        SET v_salary_amount = 0;
    END IF;

    -- =========================
    -- OUTPUT
    -- =========================
    SELECT 
        p_employee_id AS employee_id,
        p_start_date as start_payroll,
        p_end_date as end_payroll ,
        p_join_date as join_date ,
        p_resign_date as resign_date ,
        v_total_work_days AS total_work_days,
        v_employee_work_days AS employee_work_days,
        v_salary_status AS salary_status,
        v_salary_amount AS salary_amount;
    
    
    -- =========================
    -- INSERT BASIC SALLARY 
    -- =========================

    
    select allowance_code,allowance_name,type,is_tax
    into v_component_code,v_component_name,v_component_type,v_is_taxable
    from mst_allowance_component where id = v_sallary_id ;
    
    delete from payroll_employee_component  
    where period_id = p_period_id and employee_id = p_employee_id 
    and component_id = v_sallary_id;
    
    INSERT INTO payroll_employee_component (
    period_id,
    component_id,
    employee_id,
    component_code,
    component_name,
    component_type,
    amount,
    is_taxable,
    remarks,
    created_at,
    created_by
	)
	VALUES (
	    p_period_id,
	    v_sallary_id,
	    p_employee_id,
	    v_component_code,
	    v_component_name,
	    v_component_type,
	    v_salary_amount,
	    v_is_taxable,
	    v_salary_status,
	    NOW(),
	    ''
	);

END ;;
DELIMITER ;
/*!50003 SET sql_mode              = @saved_sql_mode */ ;
/*!50003 SET character_set_client  = @saved_cs_client */ ;
/*!50003 SET character_set_results = @saved_cs_results */ ;
/*!50003 SET collation_connection  = @saved_col_connection */ ;
/*!50003 DROP PROCEDURE IF EXISTS `sp_calc_manual_component` */;
/*!50003 SET @saved_cs_client      = @@character_set_client */ ;
/*!50003 SET @saved_cs_results     = @@character_set_results */ ;
/*!50003 SET @saved_col_connection = @@collation_connection */ ;
/*!50003 SET character_set_client  = utf8mb4 */ ;
/*!50003 SET character_set_results = utf8mb4 */ ;
/*!50003 SET collation_connection  = utf8mb4_general_ci */ ;
/*!50003 SET @saved_sql_mode       = @@sql_mode */ ;
/*!50003 SET sql_mode              = 'IGNORE_SPACE,STRICT_TRANS_TABLES,ERROR_FOR_DIVISION_BY_ZERO,NO_AUTO_CREATE_USER,NO_ENGINE_SUBSTITUTION' */ ;
DELIMITER ;;
CREATE DEFINER=`root`@`localhost` PROCEDURE `sp_calc_manual_component`(
    IN p_employee_id BIGINT,
    IN p_period_id INT
)
BEGIN
    -- =========================
    -- DECLARE
    -- =========================
    DECLARE done INT DEFAULT 0;

    DECLARE v_allowance_id BIGINT;
    DECLARE v_salary_amount DECIMAL(18,2);

    DECLARE v_component_code VARCHAR(255);
    DECLARE v_component_name VARCHAR(255);
    DECLARE v_component_type VARCHAR(10);
    DECLARE v_is_taxable TINYINT;

    -- =========================
    -- CURSOR
    -- =========================
    DECLARE cur_manual CURSOR FOR
        SELECT 
            pem.allowance_id,
            pem.amount
        FROM payroll_employee_manual pem
        WHERE pem.employee_id = p_employee_id
          AND pem.period_id = p_period_id;

    DECLARE CONTINUE HANDLER FOR NOT FOUND SET done = 1;

    -- =========================
    -- OPEN CURSOR
    -- =========================
    OPEN cur_manual;

    read_loop: LOOP

        FETCH cur_manual INTO v_allowance_id, v_salary_amount;

        IF done = 1 THEN
            LEAVE read_loop;
        END IF;

        -- =========================
        -- GET MASTER COMPONENT
        -- =========================
        SELECT 
            mac.allowance_code,
            mac.allowance_name,
            mac.`type`,
            mac.is_tax
        INTO 
            v_component_code,
            v_component_name,
            v_component_type,
            v_is_taxable
        FROM mst_allowance_component mac
        WHERE mac.id = v_allowance_id;

        -- =========================
        -- INSERT / UPSERT
        -- =========================
        INSERT INTO payroll_employee_component (
            period_id,
            component_id,
            employee_id,
            component_code,
            component_name,
            component_type,
            amount,
            is_taxable,
            remarks,
            created_at,
            created_by
        )
        VALUES (
            p_period_id,
            v_allowance_id,
            p_employee_id,
            v_component_code,
            v_component_name,
            v_component_type,
            v_salary_amount,
            v_is_taxable,
            'MANUAL',
            NOW(),
            ''
        )
        ON DUPLICATE KEY UPDATE
            component_code = VALUES(component_code),
            component_name = VALUES(component_name),
            component_type = VALUES(component_type),
            amount = VALUES(amount),
            is_taxable = VALUES(is_taxable),
            remarks = 'MANUAL',
            created_at = NOW();

    END LOOP;

    CLOSE cur_manual;
END ;;
DELIMITER ;
/*!50003 SET sql_mode              = @saved_sql_mode */ ;
/*!50003 SET character_set_client  = @saved_cs_client */ ;
/*!50003 SET character_set_results = @saved_cs_results */ ;
/*!50003 SET collation_connection  = @saved_col_connection */ ;
/*!50003 DROP PROCEDURE IF EXISTS `sp_calc_membership` */;
/*!50003 SET @saved_cs_client      = @@character_set_client */ ;
/*!50003 SET @saved_cs_results     = @@character_set_results */ ;
/*!50003 SET @saved_col_connection = @@collation_connection */ ;
/*!50003 SET character_set_client  = utf8mb4 */ ;
/*!50003 SET character_set_results = utf8mb4 */ ;
/*!50003 SET collation_connection  = utf8mb4_general_ci */ ;
/*!50003 SET @saved_sql_mode       = @@sql_mode */ ;
/*!50003 SET sql_mode              = 'IGNORE_SPACE,STRICT_TRANS_TABLES,ERROR_FOR_DIVISION_BY_ZERO,NO_AUTO_CREATE_USER,NO_ENGINE_SUBSTITUTION' */ ;
DELIMITER ;;
CREATE DEFINER=`root`@`localhost` PROCEDURE `sp_calc_membership`(
    IN p_employee_id BIGINT,
    IN p_period_id INT,
    IN p_start_date DATE,
    IN p_end_date DATE
)
BEGIN

    -- =========================
    -- DECLARE
    -- =========================
    DECLARE v_membership_id BIGINT;
    DECLARE v_allowance_id BIGINT;

    DECLARE v_calc_type VARCHAR(20);
    DECLARE v_base_type VARCHAR(50);
    DECLARE v_value DECIMAL(10,4);
    DECLARE v_max_amount DECIMAL(18,2);

    DECLARE v_component_code VARCHAR(50);
    DECLARE v_component_name VARCHAR(100);
    DECLARE v_component_type VARCHAR(1);
    DECLARE v_is_taxable TINYINT;

    DECLARE v_basic_salary DECIMAL(18,2);
    DECLARE v_base_amount DECIMAL(18,2);
    DECLARE v_result_amount DECIMAL(18,2);

    DECLARE done INT DEFAULT 0;

    -- =========================
    -- CURSOR
    -- =========================
    DECLARE cur_membership CURSOR FOR
        SELECT 
            m.membership_id,
            m.membership_id   -- ✅ FIX: pakai mapping bener
        FROM mst_employee_membership em
        JOIN vw_membership_rate_active m 
        WHERE 
            em.employee_id = p_employee_id
            AND em.is_active = 1
            AND em.start_date <= p_end_date
            AND IFNULL(em.end_date, p_end_date) >= p_start_date;

    DECLARE CONTINUE HANDLER FOR NOT FOUND SET done = 1;

    -- =========================
    -- BASIC SALARY
    -- =========================
    SELECT basic_salary
    INTO v_basic_salary
    FROM vw_employee_basic_salary_by_date
    WHERE employee_id = p_employee_id
    AND salary_start_date <= p_end_date
    AND IFNULL(salary_end_date, p_end_date) >= p_start_date
    ORDER BY salary_start_date DESC
    LIMIT 1;

    SET v_basic_salary = IFNULL(v_basic_salary, 0);

    -- =========================
    -- LOOP
    -- =========================
    OPEN cur_membership;

    read_loop: LOOP

        FETCH cur_membership INTO v_membership_id, v_allowance_id;

        IF done THEN
            LEAVE read_loop;
        END IF;

        -- =========================
        -- MASTER MEMBERSHIP
        -- =========================
        SELECT 
            calculation_type,
            base_type
        INTO 
            v_calc_type,
            v_base_type
        FROM mst_membership
        WHERE membership_id = v_membership_id;

        -- =========================
        -- RATE (AMBIL TERBARU)
        -- =========================
        SELECT 
            value,
            max_amount
        INTO 
            v_value,
            v_max_amount
        FROM mst_membership_rate
        WHERE membership_id = v_membership_id
        AND start_date <= p_end_date
        AND IFNULL(end_date, p_end_date) >= p_start_date
        ORDER BY start_date DESC
        LIMIT 1;

        -- 🔥 HANDLE NULL RATE
        IF v_value IS NULL THEN
            SET v_value = 0;
        END IF;

        -- =========================
        -- COMPONENT
        -- =========================
        SELECT 
            allowance_code,
            allowance_name,
            type,
            is_tax
        INTO 
            v_component_code,
            v_component_name,
            v_component_type,
            v_is_taxable
        FROM mst_allowance_component
        WHERE id = v_allowance_id;

        -- =========================
        -- BASE AMOUNT
        -- =========================
        IF v_base_type = 'BASIC_SALARY' THEN
            SET v_base_amount = v_basic_salary;
        ELSE
            SET v_base_amount = v_basic_salary; -- fallback
        END IF;

        -- plafon
        IF v_max_amount IS NOT NULL THEN
            SET v_base_amount = LEAST(v_base_amount, v_max_amount);
        END IF;

        -- =========================
        -- HITUNG
        -- =========================
        IF v_calc_type = 'PERCENT' THEN
            SET v_result_amount = ROUND(
                v_base_amount * (v_value / 100),
                2
            );
        ELSE
            SET v_result_amount = v_value;
        END IF;

        -- =========================
        -- DELETE
        -- =========================
        DELETE FROM payroll_employee_component
        WHERE 
            period_id = p_period_id
            AND employee_id = p_employee_id
            AND component_id = v_allowance_id;

        -- =========================
        -- INSERT
        -- =========================
        INSERT INTO payroll_employee_component (
            period_id,
            component_id,
            employee_id,
            component_code,
            component_name,
            component_type,
            amount,
            is_taxable,
            remarks,
            created_at,
            created_by
        )
        VALUES (
            p_period_id,
            v_allowance_id,
            p_employee_id,
            v_component_code,
            v_component_name,
            v_component_type,
            v_result_amount,
            v_is_taxable,
            'MEMBERSHIP',
            NOW(),
            ''
        );

    END LOOP;

    CLOSE cur_membership;

END ;;
DELIMITER ;
/*!50003 SET sql_mode              = @saved_sql_mode */ ;
/*!50003 SET character_set_client  = @saved_cs_client */ ;
/*!50003 SET character_set_results = @saved_cs_results */ ;
/*!50003 SET collation_connection  = @saved_col_connection */ ;
/*!50003 DROP PROCEDURE IF EXISTS `sp_calc_pph21` */;
/*!50003 SET @saved_cs_client      = @@character_set_client */ ;
/*!50003 SET @saved_cs_results     = @@character_set_results */ ;
/*!50003 SET @saved_col_connection = @@collation_connection */ ;
/*!50003 SET character_set_client  = utf8mb4 */ ;
/*!50003 SET character_set_results = utf8mb4 */ ;
/*!50003 SET collation_connection  = utf8mb4_general_ci */ ;
/*!50003 SET @saved_sql_mode       = @@sql_mode */ ;
/*!50003 SET sql_mode              = 'IGNORE_SPACE,STRICT_TRANS_TABLES,ERROR_FOR_DIVISION_BY_ZERO,NO_AUTO_CREATE_USER,NO_ENGINE_SUBSTITUTION' */ ;
DELIMITER ;;
CREATE DEFINER=`root`@`localhost` PROCEDURE `sp_calc_pph21`(
    IN p_employee_id BIGINT,
    IN p_period_id INT,
    IN p_start_date DATE,
    IN p_end_date DATE,
    IN p_resign_date DATE
)
BEGIN

    -- =========================
    -- DECLARE
    -- =========================
    DECLARE v_gross DECIMAL(18,2) DEFAULT 0;
    DECLARE v_rate DECIMAL(10,4) DEFAULT 0;
    DECLARE v_pph21 DECIMAL(18,2) DEFAULT 0;

    DECLARE v_ptkp_code VARCHAR(10);
    DECLARE v_npwp VARCHAR(50);

    DECLARE v_is_final INT DEFAULT 0;

    DECLARE v_biaya_percent DECIMAL(5,2);
    DECLARE v_biaya_max DECIMAL(18,2);
    DECLARE v_npwp_factor DECIMAL(5,2);

    DECLARE v_biaya_jabatan DECIMAL(18,2) DEFAULT 0;
    DECLARE v_bpjs DECIMAL(18,2) DEFAULT 0;
    DECLARE v_bpjs_jhtjp DECIMAL(18,2) DEFAULT 0;
    DECLARE v_netto DECIMAL(18,2) DEFAULT 0;
    DECLARE v_netto_yearly DECIMAL(18,2) DEFAULT 0;
    DECLARE v_ptkp DECIMAL(18,2) DEFAULT 0;
    DECLARE v_pkp DECIMAL(18,2) DEFAULT 0;
    DECLARE v_pph21_yearly DECIMAL(18,2) DEFAULT 0;
    DECLARE v_pph21_paid DECIMAL(18,2) DEFAULT 0;

    DECLARE v_is_npwp BIT DEFAULT 1;

    -- =========================
    -- EMPLOYEE INFO
    -- =========================
    SELECT ptkp_code, npwp
    INTO v_ptkp_code, v_npwp
    FROM vw_employee
    WHERE employee_id = p_employee_id;

    IF v_npwp IS NULL OR v_npwp = '' THEN
        SET v_is_npwp = 0;
    END IF;

    -- =========================
    -- CONFIG
    -- =========================
    SELECT value INTO v_biaya_percent 
    FROM mst_tax_config 
    WHERE config_code = 'BIAYA_JABATAN_PERCENT'
    ORDER BY effective_date DESC LIMIT 1;

    SELECT value INTO v_biaya_max 
    FROM mst_tax_config 
    WHERE config_code = 'BIAYA_JABATAN_MAX'
    ORDER BY effective_date DESC LIMIT 1;

    SELECT value INTO v_npwp_factor 
    FROM mst_tax_config 
    WHERE config_code = 'NPWP_RATE_FACTOR'
    ORDER BY effective_date DESC LIMIT 1;

    -- =========================
    -- DETECT FINAL
    -- =========================
    IF MONTH(p_end_date) = 12 THEN
        SET v_is_final = 1;
    END IF;

    IF p_resign_date IS NOT NULL 
       AND p_resign_date BETWEEN p_start_date AND p_end_date THEN
        SET v_is_final = 1;
    END IF;

    -- =========================
    -- GROSS BULAN INI
    -- =========================
    SELECT IFNULL(SUM(amount),0)
    INTO v_gross
    FROM vw_payroll_component
    WHERE employee_id = p_employee_id
    AND period_id = p_period_id
    AND is_tax = 1;

    -- =========================
    -- BPJS EMPLOYEE
    -- =========================
    SELECT IFNULL(SUM(amount),0)
    INTO v_bpjs
    FROM vw_payroll_component
    WHERE employee_id = p_employee_id
    AND period_id = p_period_id
    and is_membership = 1 and is_gross = 1 and is_tax = 1 ;
    
    -- =========================
    -- BPJS JHT JP EMPLOYEE
    -- =========================
    SELECT IFNULL(SUM(amount),0)
    INTO v_bpjs_jhtjp
    FROM vw_payroll_component
    WHERE employee_id = p_employee_id
    AND period_id = p_period_id and component_code in ('JHT_EMP','JP_EMP') ;
	--     AND component_type = 'EMPLOYEE';

    -- =====================================================
    -- ================= TER (BULANAN) =====================
    -- =====================================================
    IF v_is_final = 0 THEN

        SELECT rate
		INTO v_rate
		FROM mst_tax_ter
		WHERE ptkp_code = v_ptkp_code
		AND v_gross >= min_salary
		AND (max_salary IS NULL OR v_gross <= max_salary)
		ORDER BY min_salary DESC
		LIMIT 1;
		
        SET v_pph21 = v_gross * (v_rate / 100);

        IF v_is_npwp = 0 THEN
            SET v_pph21 = v_pph21 * v_npwp_factor;
        END IF;

--         select v_gross,v_rate,v_ptkp_code,v_pph21;
    END IF;

    -- =====================================================
    -- ============ FINAL (DESEMBER / RESIGN) ==============
    -- =====================================================
    IF v_is_final = 1 THEN

        -- =========================
        -- GROSS SETAHUN
        -- =========================
        SELECT IFNULL(SUM(amount),0)
        INTO v_gross
        FROM vw_payroll_component
        WHERE employee_id = p_employee_id
        AND YEAR(pay_date) = YEAR(p_end_date)
        AND is_tax = 1;

        -- =========================
        -- BPJS SETAHUN
        -- =========================
        SELECT IFNULL(SUM(amount),0)
        INTO v_bpjs
        FROM vw_payroll_component
        WHERE employee_id = p_employee_id
        AND YEAR(pay_date) = YEAR(p_end_date)
        and is_membership = 1 and is_gross = 1 and is_tax = 1 ;
--         AND component_type = 'EMPLOYEE';
        
        -- =========================
	    -- BPJS JHT JP SETAHUN
	    -- =========================
	    SELECT IFNULL(SUM(amount),0)
	    INTO v_bpjs_jhtjp
	    FROM vw_payroll_component
	    WHERE employee_id = p_employee_id
	    AND YEAR(pay_date) = YEAR(p_end_date)
	    AND  component_code in ('JHT_EMP','JP_EMP') ;

        -- =========================
        -- BIAYA JABATAN
        -- =========================
        SET v_biaya_jabatan = LEAST(
            v_gross * (v_biaya_percent / 100),
            v_biaya_max * 12
        );

        -- =========================
        -- NETTO
        -- =========================
        SET v_netto = v_gross - v_biaya_jabatan - v_bpjs_jhtjp;
        SET v_netto_yearly = v_netto;

        -- =========================
        -- PTKP
        -- =========================
        SELECT amount INTO v_ptkp
        FROM mst_tax_ptkp
        WHERE ptkp_code = v_ptkp_code
        ORDER BY effective_date DESC LIMIT 1;

        -- =========================
        -- PKP
        -- =========================
        SET v_pkp = GREATEST(v_netto_yearly - v_ptkp, 0);
        SET v_pkp = (v_pkp / 1000) * 1000;

        -- =========================
        -- PROGRESSIVE TAX
        -- =========================
        SELECT SUM(
            (LEAST(v_pkp, IFNULL(max_amount, v_pkp)) - min_amount) * rate / 100
        )
        INTO v_pph21_yearly
        FROM mst_tax_bracket
        WHERE v_pkp > min_amount;

        -- =========================
        -- NPWP
        -- =========================
        IF v_is_npwp = 0 THEN
            SET v_pph21_yearly = v_pph21_yearly * v_npwp_factor;
        END IF;


        -- =========================
        -- PAJAK SUDAH DIBAYAR
        -- =========================
        SELECT IFNULL(SUM(amount),0)
        INTO v_pph21_paid
        FROM vw_payroll_component
        WHERE employee_id = p_employee_id
        AND component_code = 'PPH21'
        AND period_id not IN (p_period_id);

        -- =========================
        -- FINAL
        -- =========================
        SET v_pph21 = v_pph21_paid - v_pph21_yearly ;

--         IF v_pph21 < 0 THEN
--             SET v_pph21 = 0;
--         END IF;

    END IF;

    -- =========================
    -- INSERT COMPONENT
    -- =========================
    DELETE FROM payroll_employee_component  
    WHERE period_id = p_period_id 
    AND employee_id = p_employee_id 
    AND component_code = 'PPH21';

    INSERT INTO payroll_employee_component (
        period_id,
        component_id,
        employee_id,
        component_code,
        component_name,
        component_type,
        amount,
        is_taxable,
        remarks,
        created_at
    )
    VALUES (
        p_period_id,
        21,
        p_employee_id,
        'PPH21',
        'PPh 21',
        '-',
        v_pph21,
        0,
        IF(v_is_final = 1, 'FINAL TAX', 'TER BULANAN'),
        NOW()
    );

    -- =========================
    -- INSERT TAX DETAIL
    -- =========================
    DELETE FROM payroll_employee_tax
    WHERE period_id = p_period_id
    AND employee_id = p_employee_id;

    INSERT INTO payroll_employee_tax (
        period_id,
        employee_id,
        tax_method,
        gross_amount,
        biaya_jabatan,
        bpjs_employee,
        bpjs_employee_jhtjp,
        netto_amount,
        netto_yearly,
        ptkp_amount,
        pkp_amount,
        tax_yearly,
        tax_paid_before,
        tax_current,
        ter_rate,
        is_npwp,
        npwp_factor,
        remarks,
        created_at,
        created_by
    )
    VALUES (
        p_period_id,
        p_employee_id,
        IF(v_is_final = 1, 'FINAL', 'TER'),
        v_gross,
        v_biaya_jabatan,
        v_bpjs,
        v_bpjs_jhtjp,
        v_netto,
        v_netto_yearly,
        v_ptkp,
        v_pkp,
        v_pph21_yearly,
        v_pph21_paid,
        v_pph21,
        v_rate,
        v_is_npwp,
        v_npwp_factor,
        IF(v_is_final = 1, 'FINAL TAX', 'TER BULANAN'),
        NOW(),
        ''
    );

END ;;
DELIMITER ;
/*!50003 SET sql_mode              = @saved_sql_mode */ ;
/*!50003 SET character_set_client  = @saved_cs_client */ ;
/*!50003 SET character_set_results = @saved_cs_results */ ;
/*!50003 SET collation_connection  = @saved_col_connection */ ;
/*!50003 DROP PROCEDURE IF EXISTS `sp_generate_employee_schedule` */;
/*!50003 SET @saved_cs_client      = @@character_set_client */ ;
/*!50003 SET @saved_cs_results     = @@character_set_results */ ;
/*!50003 SET @saved_col_connection = @@collation_connection */ ;
/*!50003 SET character_set_client  = utf8mb4 */ ;
/*!50003 SET character_set_results = utf8mb4 */ ;
/*!50003 SET collation_connection  = utf8mb4_general_ci */ ;
/*!50003 SET @saved_sql_mode       = @@sql_mode */ ;
/*!50003 SET sql_mode              = 'IGNORE_SPACE,STRICT_TRANS_TABLES,ERROR_FOR_DIVISION_BY_ZERO,NO_AUTO_CREATE_USER,NO_ENGINE_SUBSTITUTION' */ ;
DELIMITER ;;
CREATE DEFINER=`root`@`localhost` PROCEDURE `sp_generate_employee_schedule`(
    IN p_shift_group_id BIGINT,
    IN p_start_date DATE,
    IN p_end_date DATE
)
BEGIN

INSERT INTO trn_employee_schedule
(
    employee_id,
    shift_id,
    work_date,
    schedule_type,
    source,
    created_at
)

SELECT
    e.employee_id,

    CASE 
        WHEN h.holiday_date IS NOT NULL THEN NULL
        ELSE spd.shift_id
    END AS shift_id,

    c.cal_date,

    CASE
        WHEN h.holiday_date IS NOT NULL THEN 'HOLIDAY'
        WHEN spd.workday = 0 THEN 'OFF'
        ELSE 'WORK'
    END AS schedule_type,

    'AUTO',
    NOW()

FROM trn_employee_shift_group e

JOIN mst_shift_pattern sp
    ON sp.shift_group_id = e.shift_group_id

JOIN mst_calendar c
    ON c.cal_date BETWEEN p_start_date AND p_end_date

LEFT JOIN mst_holiday h
    ON h.holiday_date = c.cal_date
    AND h.is_active = 1

JOIN mst_shift_pattern_detail spd
    ON spd.pattern_id = sp.pattern_id
    AND spd.day_sequence =
    (
        MOD(
            DATEDIFF(c.cal_date, sp.pattern_start_date), -- ✅ tetap pattern
            sp.cycle_days
        ) + 1
    )

WHERE e.shift_group_id = p_shift_group_id

-- ✅ hanya mulai dari employee join
AND c.cal_date >= e.start_date

-- ✅ support histori
AND (e.end_date IS NULL OR c.cal_date <= e.end_date)

ON DUPLICATE KEY UPDATE
    shift_id = VALUES(shift_id),
    schedule_type = VALUES(schedule_type),
    source = 'AUTO',
    updated_at = NOW();

END ;;
DELIMITER ;
/*!50003 SET sql_mode              = @saved_sql_mode */ ;
/*!50003 SET character_set_client  = @saved_cs_client */ ;
/*!50003 SET character_set_results = @saved_cs_results */ ;
/*!50003 SET collation_connection  = @saved_col_connection */ ;
/*!50003 DROP PROCEDURE IF EXISTS `sp_generate_payroll` */;
/*!50003 SET @saved_cs_client      = @@character_set_client */ ;
/*!50003 SET @saved_cs_results     = @@character_set_results */ ;
/*!50003 SET @saved_col_connection = @@collation_connection */ ;
/*!50003 SET character_set_client  = utf8mb4 */ ;
/*!50003 SET character_set_results = utf8mb4 */ ;
/*!50003 SET collation_connection  = utf8mb4_general_ci */ ;
/*!50003 SET @saved_sql_mode       = @@sql_mode */ ;
/*!50003 SET sql_mode              = 'IGNORE_SPACE,STRICT_TRANS_TABLES,ERROR_FOR_DIVISION_BY_ZERO,NO_AUTO_CREATE_USER,NO_ENGINE_SUBSTITUTION' */ ;
DELIMITER ;;
CREATE DEFINER=`root`@`localhost` PROCEDURE `sp_generate_payroll`(IN p_period_id INT, IN p_employee_id BIGINT)
begin
	declare v_start_payroll date ; 
	declare v_end_payroll date ;
    declare v_pay_date date ;
	declare v_grade_id varchar(100);
    declare v_is_proporsional_day varchar(100);
	declare v_position_id varchar(100) ;
	declare v_working_id  varchar(100);
	declare v_education_id varchar(100);
    declare v_join_date date ;
	declare v_resign_date date ;

	-- delete all payroll
	delete from payroll_employee_component where period_id = p_period_id and employee_id=p_employee_id;

	-- ambil tanggal perhitungan payroll 
    select start_date ,end_date ,pay_date ,is_proporsional_day
        into v_start_payroll,v_end_payroll,v_pay_date,v_is_proporsional_day
    from payroll_period  
    where period_id =p_period_id ;

 	-- ambil data employee 
	select grade_id , position_id,working_id,education_id,join_date ,resign_date
	into v_grade_id,v_position_id,v_working_id,v_education_id,v_join_date,v_resign_date
	from vw_employee 
	where employee_id = p_employee_id ;
 	
 	
	-- Hitung Basic Sallary 
 	call sp_calc_basic_salary(p_employee_id ,v_start_payroll ,v_end_payroll ,v_join_date ,v_resign_date ,p_period_id);
	
	-- Hitung Daily Allowance
	call sp_calc_allowance_daily(p_employee_id,v_start_payroll,v_end_payroll,p_period_id);
	
	-- Hitung Monthly Allowance
	call sp_calc_allowance_monthly(p_employee_id,p_period_id,v_position_id,v_grade_id,v_working_id,v_education_id, v_start_payroll, v_end_payroll,v_join_date, v_resign_date);
	
	-- Hitung Membership 
	call sp_calc_membership(p_employee_id,p_period_id,v_start_payroll,v_end_payroll);
	
	
	-- Hitung Manual Sallary 
	call sp_calc_manual_component(p_employee_id,p_period_id);
	
	-- Hitung Pajak nya 
	 call sp_calc_pph21(p_employee_id,p_period_id,v_start_payroll,v_end_payroll,v_resign_date);

end ;;
DELIMITER ;
/*!50003 SET sql_mode              = @saved_sql_mode */ ;
/*!50003 SET character_set_client  = @saved_cs_client */ ;
/*!50003 SET character_set_results = @saved_cs_results */ ;
/*!50003 SET collation_connection  = @saved_col_connection */ ;
/*!50003 DROP PROCEDURE IF EXISTS `sp_insert_allowance_attendance` */;
/*!50003 SET @saved_cs_client      = @@character_set_client */ ;
/*!50003 SET @saved_cs_results     = @@character_set_results */ ;
/*!50003 SET @saved_col_connection = @@collation_connection */ ;
/*!50003 SET character_set_client  = utf8mb4 */ ;
/*!50003 SET character_set_results = utf8mb4 */ ;
/*!50003 SET collation_connection  = utf8mb4_general_ci */ ;
/*!50003 SET @saved_sql_mode       = @@sql_mode */ ;
/*!50003 SET sql_mode              = 'IGNORE_SPACE,STRICT_TRANS_TABLES,ERROR_FOR_DIVISION_BY_ZERO,NO_AUTO_CREATE_USER,NO_ENGINE_SUBSTITUTION' */ ;
DELIMITER ;;
CREATE DEFINER=`root`@`localhost` PROCEDURE `sp_insert_allowance_attendance`(
    IN p_employee_id BIGINT,
    IN p_shift_id BIGINT,
    IN p_work_date DATE
)
BEGIN

    DECLARE done INT DEFAULT FALSE;

    DECLARE v_allowance_id BIGINT;
    DECLARE v_amount VARCHAR(100);

    -- Cursor ambil semua allowance
    DECLARE cur_allowance CURSOR FOR
        SELECT 
            allowance_id,
            REPLACE(amount, ',', '')
        FROM mst_shift_allowance
        WHERE shift_id = p_shift_id
          AND p_work_date >= start_date
          AND (end_date IS NULL OR p_work_date <= end_date);

    DECLARE CONTINUE HANDLER FOR NOT FOUND SET done = TRUE;

    OPEN cur_allowance;

    read_loop: LOOP

        FETCH cur_allowance INTO v_allowance_id, v_amount;

        IF done THEN
            LEAVE read_loop;
        END IF;

        -- Hindari duplicate
        IF NOT EXISTS (
            SELECT 1 
            FROM trn_attendance_allowance
            WHERE employee_id = p_employee_id
              AND work_date = p_work_date
              AND allowance_id = v_allowance_id
        ) THEN

            INSERT INTO trn_attendance_allowance (
                employee_id,
                work_date,
                allowance_id,
                amount,
                created_at
            )
            VALUES (
                p_employee_id,
                p_work_date,
                v_allowance_id,
                v_amount,
                NOW()
            );

        END IF;

    END LOOP;

    CLOSE cur_allowance;

END ;;
DELIMITER ;
/*!50003 SET sql_mode              = @saved_sql_mode */ ;
/*!50003 SET character_set_client  = @saved_cs_client */ ;
/*!50003 SET character_set_results = @saved_cs_results */ ;
/*!50003 SET collation_connection  = @saved_col_connection */ ;
/*!50003 DROP PROCEDURE IF EXISTS `sp_insert_allowance_position` */;
/*!50003 SET @saved_cs_client      = @@character_set_client */ ;
/*!50003 SET @saved_cs_results     = @@character_set_results */ ;
/*!50003 SET @saved_col_connection = @@collation_connection */ ;
/*!50003 SET character_set_client  = utf8mb4 */ ;
/*!50003 SET character_set_results = utf8mb4 */ ;
/*!50003 SET collation_connection  = utf8mb4_general_ci */ ;
/*!50003 SET @saved_sql_mode       = @@sql_mode */ ;
/*!50003 SET sql_mode              = 'IGNORE_SPACE,STRICT_TRANS_TABLES,ERROR_FOR_DIVISION_BY_ZERO,NO_AUTO_CREATE_USER,NO_ENGINE_SUBSTITUTION' */ ;
DELIMITER ;;
CREATE DEFINER=`root`@`localhost` PROCEDURE `sp_insert_allowance_position`(
    IN p_employee_id BIGINT,
    IN p_position_id VARCHAR(50),
    IN p_grade_id VARCHAR(50),
    IN p_working_id VARCHAR(50),
    IN p_education_id VARCHAR(50),
    IN p_work_date DATE
)
BEGIN

    DECLARE done INT DEFAULT FALSE;

    DECLARE v_allowance_id BIGINT;
    DECLARE v_amount VARCHAR(100);

    -- Cursor ambil allowance berdasarkan position
    DECLARE cur_allowance CURSOR FOR
        SELECT 
            allowance_id,
            REPLACE(amount, ',', '')
        FROM mst_allowance_position
        WHERE position_id = p_position_id
          AND grade_id = p_grade_id
          AND working_id = p_working_id
          AND education_id = p_education_id
          AND is_daily = 1
          AND p_work_date >= start_date
          AND (end_date IS NULL OR p_work_date <= end_date);

    DECLARE CONTINUE HANDLER FOR NOT FOUND SET done = TRUE;

    OPEN cur_allowance;

    read_loop: LOOP

        FETCH cur_allowance INTO v_allowance_id, v_amount;

        IF done THEN
            LEAVE read_loop;
        END IF;

        -- Hindari duplicate
        IF NOT EXISTS (
            SELECT 1 
            FROM trn_attendance_allowance
            WHERE employee_id = p_employee_id
              AND work_date = p_work_date
              AND allowance_id = v_allowance_id
        ) THEN

            INSERT INTO trn_attendance_allowance (
                employee_id,
                work_date,
                allowance_id,
                amount,
                created_at
            )
            VALUES (
                p_employee_id,
                p_work_date,
                v_allowance_id,
                v_amount,
                NOW()
            );

        END IF;

    END LOOP;

    CLOSE cur_allowance;

END ;;
DELIMITER ;
/*!50003 SET sql_mode              = @saved_sql_mode */ ;
/*!50003 SET character_set_client  = @saved_cs_client */ ;
/*!50003 SET character_set_results = @saved_cs_results */ ;
